import java.util.*;class Player{static String[]R=new String[4];static int PL,NB,MB;static boolean h0(int i,int a,int b){for(int j=a;j<b&&j<PL;j++)if(R[i].charAt(j)=='0')return true;return false;}static int[]sim(int[]s,String act){int[]n={s[0],s[1],s[2],s[3],s[4],s[5]};if(act.equals("SPEED"))n[5]++;if(act.equals("SLOW"))n[5]--;if(act.equals("SPEED")||act.equals("SLOW")||act.equals("WAIT")){for(int i=0;i<4;i++)if(n[i]==1&&h0(i,n[4],n[4]+n[5]))n[i]=0;n[4]+=n[5];}else if(act.equals("JUMP")){for(int i=0;i<4;i++)if(n[i]==1&&(R[i].charAt(n[4])=='0'||(n[4]+n[5]<PL&&R[i].charAt(n[4]+n[5])=='0')))n[i]=0;n[4]+=n[5];}else if(act.equals("UP")){if(n[0]==1){for(int i=0;i<4;i++)if(n[i]==1&&h0(i,n[4],n[4]+n[5]))n[i]=0;}else for(int i=1;i<4;i++){if(n[i-1]==0&&n[i]==1){if(h0(i-1,n[4],n[4]+n[5])||h0(i,n[4],n[4]+n[5])){n[i-1]=0;n[i]=0;}else{n[i-1]=1;n[i]=0;}}else if(n[i-1]==1&&n[i]==1){if(h0(i-1,n[4],n[4]+n[5]))n[i-1]=0;if(h0(i,n[4],n[4]+n[5]))n[i]=0;}}n[4]+=n[5];}else{if(n[3]==1){for(int i=0;i<4;i++)if(n[i]==1&&h0(i,n[4],n[4]+n[5]))n[i]=0;}else for(int i=2;i>=0;i--){if(n[i+1]==0&&n[i]==1){if(h0(i,n[4],n[4]+n[5])||h0(i+1,n[4],n[4]+n[5])){n[i+1]=0;n[i]=0;}else{n[i+1]=1;n[i]=0;}}else if(n[i+1]==1&&n[i]==1){if(h0(i+1,n[4],n[4]+n[5]))n[i+1]=0;if(h0(i,n[4],n[4]+n[5]))n[i]=0;}}n[4]+=n[5];}return n;}public static void main(String[]a){var sc=new Scanner(System.in);NB=sc.nextInt();MB=sc.nextInt();sc.nextLine();for(int i=0;i<4;i++)R[i]=sc.nextLine()+".".repeat(50);PL=R[0].length();String[]AN={"SPEED","JUMP","WAIT","UP","DOWN","SLOW"};var F=new ArrayList<String>();for(;;){if(!F.isEmpty()){sc.nextInt();for(int i=0;i<NB;i++){sc.nextInt();sc.nextInt();sc.nextInt();}System.out.println(F.remove(0));continue;}int sp=sc.nextInt();int[]L=new int[4];int bx=0;for(int i=0;i<NB;i++){int x=sc.nextInt(),y=sc.nextInt(),v=sc.nextInt();L[y]=v;if(v==1)bx=x;}var q=new ArrayList<Object[]>();q.add(new Object[]{new int[]{L[0],L[1],L[2],L[3],bx,sp},new ArrayList<String>()});int[]best=null;List<String>ba=null;for(int it=0;it<30&&!q.isEmpty();it++){var nq=new ArrayList<Object[]>();for(var st:q){int[]ss=(int[])st[0];for(var act:AN){int[]r=sim(ss,act);int nb=r[0]+r[1]+r[2]+r[3];if(nb<MB||r[5]<1)continue;var ca=new ArrayList<>((List<String>)st[1]);ca.add(act);if(r[4]>=PL-30){if(best==null||nb>best[0]+best[1]+best[2]+best[3]){best=r;ba=ca;}continue;}nq.add(new Object[]{r,ca});}}nq.sort((x,y)->{int[]xs=(int[])x[0],ys=(int[])y[0];return(ys[0]+ys[1]+ys[2]+ys[3])*ys[4]-(xs[0]+xs[1]+xs[2]+xs[3])*xs[4];});if(nq.size()>200)nq.subList(200,nq.size()).clear();q=nq;if(best!=null)break;}F=ba!=null?ba:new ArrayList<>(List.of("SPEED"));System.out.println(F.remove(0));}}}
